class Solution:
    def convertPrefixToInfix(self, prefix: str) -> str:
        stack = []
        prefix = prefix[::-1]

        for char in prefix:
            if char.isalpha():
                stack.append(char)
            else:
                operand1 = stack.pop()
                operand2 = stack.pop()
                infix = f"({operand1}{char}{operand2})"
                stack.append(infix)

