#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    string convertPrefixToInfix(string prefix) {
        stack<string> s;
        reverse(prefix.begin(), prefix.end());

        for (char c : prefix) {
            if (isalpha(c)) {
                s.push(string(1, c));
            } else {
                string op1 = s.top();
                s.pop();
                string op2 = s.top();
                s.pop();
                string infix = "(" + op1 + c + op2 + ")";
                s.push(infix);
            }
        }

        return s.top();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string prefix;
    if (!(cin >> prefix)) return 0;
    Solution sol;
    string ans = sol.convertPrefixToInfix(prefix);
    cout << ans << endl;
    return 0;
}
